const BASE = '/accounting';
const MASTER = '/master';

const qsFilter = (filter?: Record<string, string | number | boolean | undefined>) => {
  const qs = new URLSearchParams();
  if (!filter) return qs;
  Object.entries(filter).forEach(([k, v]) => {
    if (v !== undefined && v !== '') qs.set(k, String(v));
  });
  return qs;
};

const unwrapList = <T>(data: T[] | PagedResult<T>): PagedResult<T> => {
  if (Array.isArray(data)) {
    return { items: data, totalCount: data.length, page: 1, pageSize: data.length || 20 };
  }
  return data;
};

